import React from "react";
import {
  Database,
  House,
  Folder,
  Orbit,
  Plug,
  PanelLeftClose,
  EllipsisVertical,
} from "lucide-react";
import { spring, useCurrentFrame, useVideoConfig, interpolate } from "remotion";
import { colors } from "../theme";

type NavKey = "overview" | "vaults" | "sources" | "connect";

const NAV: { key: NavKey; label: string; Icon: React.ComponentType<{ size?: number; color?: string; strokeWidth?: number }> }[] = [
  { key: "overview", label: "Overview", Icon: House },
  { key: "vaults", label: "Context vaults", Icon: Folder },
  { key: "sources", label: "Data sources", Icon: Orbit },
  { key: "connect", label: "Connect", Icon: Plug },
];

export const AppShell: React.FC<{
  active: NavKey;
  children: React.ReactNode;
  brand?: string;
}> = ({ active, children, brand = "The Layer" }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Sidebar slides in
  const slide = spring({
    frame,
    fps,
    config: { damping: 22, stiffness: 110, mass: 0.6 },
  });
  const sidebarX = interpolate(slide, [0, 1], [-310, 0]);

  return (
    <div
      style={{
        display: "flex",
        width: "100%",
        height: "100%",
        background: colors.background,
        overflow: "hidden",
      }}
    >
      {/* Sidebar */}
      <aside
        style={{
          width: 310,
          flexShrink: 0,
          display: "flex",
          flexDirection: "column",
          borderRight: `1px solid ${colors.sidebarBorder}`,
          background: colors.sidebar,
          height: "100%",
          padding: 22,
          transform: `translateX(${sidebarX}px)`,
        }}
      >
        {/* Logo row */}
        <div
          style={{
            height: 40,
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            marginBottom: 20,
            flexShrink: 0,
            opacity: interpolate(frame, [4, 16], [0, 1], { extrapolateRight: "clamp" }),
          }}
        >
          <div style={{ display: "flex", alignItems: "center", gap: 9 }}>
            <div
              style={{
                width: 28,
                height: 28,
                borderRadius: 8,
                background: "#0a0a0a",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                flexShrink: 0,
              }}
            >
              <Database size={13} color="white" strokeWidth={2.2} />
            </div>
            <span
              style={{
                fontSize: 14,
                fontWeight: 700,
                letterSpacing: "-0.02em",
                color: colors.fg,
                whiteSpace: "nowrap",
              }}
            >
              {brand}
            </span>
          </div>
          <div
            style={{
              width: 28,
              height: 28,
              borderRadius: 8,
              border: "1px solid #d6d6da",
              background: colors.sidebar,
              color: "#666",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <PanelLeftClose size={15} />
          </div>
        </div>

        {/* Nav */}
        <nav style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {NAV.map((item, i) => {
            const isActive = item.key === active;
            const navOpacity = interpolate(frame, [8 + i * 3, 20 + i * 3], [0, 1], {
              extrapolateRight: "clamp",
            });
            const navX = interpolate(frame, [8 + i * 3, 20 + i * 3], [-8, 0], {
              extrapolateRight: "clamp",
            });
            return (
              <div
                key={item.key}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 12,
                  padding: "12px 14px",
                  borderRadius: 12,
                  fontSize: 16.5,
                  background: isActive ? colors.navActiveBg : "transparent",
                  color: isActive ? colors.navActiveFg : colors.fgMuted,
                  fontWeight: isActive ? 500 : 400,
                  whiteSpace: "nowrap",
                  opacity: navOpacity,
                  transform: `translateX(${navX}px)`,
                }}
              >
                <item.Icon size={21} strokeWidth={isActive ? 2.1 : 1.9} />
                {item.label}
              </div>
            );
          })}
        </nav>

        {/* User row */}
        <div
          style={{
            marginTop: "auto",
            borderTop: "1px solid #e4e4e7",
            paddingTop: 14,
            opacity: interpolate(frame, [18, 30], [0, 1], { extrapolateRight: "clamp" }),
          }}
        >
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div
              style={{
                width: 40,
                height: 40,
                borderRadius: "50%",
                flexShrink: 0,
                background: "linear-gradient(135deg, #c7d2fe, #818cf8)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontSize: 13,
                fontWeight: 700,
                color: "#3730a3",
              }}
            >
              NK
            </div>
            <div style={{ minWidth: 0, flex: 1 }}>
              <p
                style={{
                  margin: 0,
                  fontSize: 14,
                  lineHeight: 1.2,
                  color: "#3f3f46",
                  fontWeight: 500,
                  whiteSpace: "nowrap",
                }}
              >
                Nikita Kowalski
              </p>
              <p
                style={{
                  margin: "2px 0 0",
                  fontSize: 12,
                  color: colors.fgSubtle,
                  whiteSpace: "nowrap",
                }}
              >
                nikita.kowalski@thelayer.ai
              </p>
            </div>
            <div
              style={{
                width: 28,
                height: 28,
                borderRadius: 8,
                background: "transparent",
                color: "#6b7280",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <EllipsisVertical size={17} />
            </div>
          </div>
        </div>
      </aside>

      {/* Main */}
      <main style={{ flex: 1, display: "flex", overflow: "hidden" }}>{children}</main>
    </div>
  );
};

