import React from "react";
import {
  AbsoluteFill,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { AppShell } from "../components/AppShell";
import { FolderSVG } from "../components/FolderSVG";
import { colors, PALETTE } from "../theme";

type Section = {
  path: string;
  label: string;
  type: keyof typeof PALETTE;
  count: number;
  items: { id: string; label: string; sentiment?: "positive" | "negative" | "neutral" }[];
};

const SECTIONS: Section[] = [
  {
    path: "people",
    label: "People",
    type: "person",
    count: 42,
    items: [
      { id: "p1", label: "Sarah Chen", sentiment: "positive" },
      { id: "p2", label: "Marcus Rivera", sentiment: "neutral" },
      { id: "p3", label: "Aisha Patel", sentiment: "positive" },
      { id: "p4", label: "Tomás Hernández", sentiment: "negative" },
      { id: "p5", label: "Lena Brandt", sentiment: "positive" },
      { id: "p6", label: "Jin Watanabe", sentiment: "neutral" },
      { id: "p7", label: "Olivia Park", sentiment: "positive" },
    ],
  },
  { path: "companies", label: "Companies", type: "company", count: 18, items: [] },
  { path: "documents", label: "Documents", type: "document", count: 127, items: [] },
  { path: "events", label: "Events", type: "event", count: 24, items: [] },
  { path: "tasks", label: "Tasks", type: "task", count: 56, items: [] },
  { path: "emails", label: "Emails", type: "email", count: 384, items: [] },
  { path: "policies", label: "Policies", type: "policy", count: 12, items: [] },
  { path: "tickets", label: "Tickets", type: "ticket", count: 73, items: [] },
];

const TOTAL = SECTIONS.reduce((s, x) => s + x.count, 0);

// Timing (frames @ 30fps)
const T_GRID_START = 32; // folders begin staggering in
const T_GRID_DONE = 90;
const T_HOVER_START = 120; // cursor moves to People folder
const T_CLICK = 150; // click triggers transition
const T_FILES_START = 165;
const T_END = 360;

const OPEN_INDEX = 0; // open the People folder

export const BrowseScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const isOpen = frame >= T_CLICK;

  return (
    <AbsoluteFill style={{ background: colors.background }}>
      <AppShell active="vaults">
        <div style={{ display: "flex", flexDirection: "column", height: "100%", flex: 1 }}>
          {/* Topbar */}
          <Topbar isOpen={isOpen} sectionLabel={SECTIONS[OPEN_INDEX].label} />

          {/* Body */}
          <div
            style={{
              flex: 1,
              overflow: "hidden",
              padding: "32px 40px",
              background: colors.background,
              position: "relative",
            }}
          >
            {!isOpen && <FolderGrid frame={frame} fps={fps} />}
            {isOpen && <FileList frame={frame} fps={fps} />}

            {/* Cursor */}
            <Cursor frame={frame} />
          </div>
        </div>
      </AppShell>
    </AbsoluteFill>
  );
};

const Topbar: React.FC<{ isOpen: boolean; sectionLabel: string }> = ({ isOpen, sectionLabel }) => {
  const frame = useCurrentFrame();
  const fadeIn = interpolate(frame, [10, 24], [0, 1], { extrapolateRight: "clamp" });
  const breadcrumbProg = interpolate(frame, [T_CLICK, T_CLICK + 12], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  return (
    <div
      style={{
        height: 52,
        flexShrink: 0,
        display: "flex",
        alignItems: "center",
        padding: "0 24px",
        borderBottom: `1px solid ${colors.border}`,
        background: "#fff",
        gap: 8,
        opacity: fadeIn,
      }}
    >
      {isOpen ? (
        <>
          <span style={{ fontSize: 14, fontWeight: 500, color: colors.fgFaint }}>
            Context vaults
          </span>
          <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
            <path
              d="M5 3l4 4-4 4"
              stroke="#ccc"
              strokeWidth="1.5"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
          <span
            style={{
              fontSize: 14,
              fontWeight: 600,
              color: colors.fg,
              opacity: breadcrumbProg,
              transform: `translateX(${interpolate(breadcrumbProg, [0, 1], [-6, 0])}px)`,
            }}
          >
            {sectionLabel}
          </span>
        </>
      ) : (
        <span style={{ fontSize: 14, fontWeight: 600, color: colors.fg }}>Context vaults</span>
      )}
      <span
        style={{
          marginLeft: "auto",
          fontSize: 11.5,
          color: colors.fgFaint,
          background: colors.pillBg,
          borderRadius: 20,
          padding: "4px 12px",
        }}
      >
        {TOTAL} entities
      </span>
    </div>
  );
};

const FolderGrid: React.FC<{ frame: number; fps: number }> = ({ frame, fps }) => {
  // Fade out the grid right before click
  const exitOpacity = interpolate(frame, [T_CLICK - 8, T_CLICK + 6], [1, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  return (
    <div
      style={{
        display: "grid",
        gridTemplateColumns: "repeat(auto-fill, minmax(240px, 1fr))",
        gap: 16,
        opacity: exitOpacity,
      }}
    >
      {SECTIONS.map((sec, i) => (
        <FolderCard key={sec.path} section={sec} index={i} frame={frame} fps={fps} />
      ))}
    </div>
  );
};

const FolderCard: React.FC<{
  section: Section;
  index: number;
  frame: number;
  fps: number;
}> = ({ section, index, frame, fps }) => {
  const start = T_GRID_START + index * 5;
  const enter = spring({
    frame: frame - start,
    fps,
    config: { damping: 18, stiffness: 140, mass: 0.7 },
  });
  const opacity = interpolate(enter, [0, 1], [0, 1]);
  const translateY = interpolate(enter, [0, 1], [20, 0]);
  const scale = interpolate(enter, [0, 1], [0.92, 1]);

  // Hover/lift on the open target right before click
  const isTarget = index === OPEN_INDEX;
  const hover = isTarget
    ? interpolate(frame, [T_HOVER_START, T_HOVER_START + 14], [0, 1], {
        extrapolateLeft: "clamp",
        extrapolateRight: "clamp",
      })
    : 0;
  const press = isTarget
    ? interpolate(frame, [T_CLICK - 3, T_CLICK + 1], [0, 1], {
        extrapolateLeft: "clamp",
        extrapolateRight: "clamp",
      })
    : 0;
  const accent = PALETTE[section.type][3];
  const lift = -2 * hover - 1 * press;
  const cardScale = scale * (1 + 0.01 * hover - 0.02 * press);

  return (
    <div
      style={{
        background: "#fff",
        border: `1.5px solid ${hover ? `${accent}66` : "transparent"}`,
        borderRadius: 18,
        padding: "18px 18px 16px",
        boxShadow: hover
          ? "0 14px 38px rgba(0,0,0,0.12)"
          : "0 1px 6px rgba(0,0,0,0.06)",
        opacity,
        transform: `translateY(${translateY + lift}px) scale(${cardScale})`,
      }}
    >
      <div style={{ position: "relative", marginBottom: 4 }}>
        <FolderSVG type={section.type} />
      </div>
      <p
        style={{
          fontSize: 15,
          fontWeight: 600,
          color: colors.fg,
          marginTop: 8,
          marginBottom: 0,
          lineHeight: 1.25,
        }}
      >
        {section.label}
      </p>
      <p style={{ fontSize: 12.5, color: colors.fgFaint, marginTop: 2, marginBottom: 0 }}>
        {section.count} entities
      </p>
    </div>
  );
};

const FileList: React.FC<{ frame: number; fps: number }> = ({ frame, fps }) => {
  const sec = SECTIONS[OPEN_INDEX];
  const enter = spring({
    frame: frame - T_FILES_START,
    fps,
    config: { damping: 22, stiffness: 130, mass: 0.7 },
  });
  const opacity = interpolate(enter, [0, 1], [0, 1]);
  const ty = interpolate(enter, [0, 1], [16, 0]);

  return (
    <div
      style={{
        background: "#fff",
        borderRadius: 14,
        overflow: "hidden",
        boxShadow: "0 1px 6px rgba(0,0,0,0.06)",
        marginBottom: 24,
        opacity,
        transform: `translateY(${ty}px)`,
      }}
    >
      {/* Column header */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 10,
          padding: "10px 14px",
          borderBottom: `1px solid ${colors.borderSoft}`,
          background: colors.columnHeaderBg,
        }}
      >
        <span
          style={{
            flex: 1,
            fontSize: 11,
            fontWeight: 600,
            textTransform: "uppercase",
            letterSpacing: "0.05em",
            color: colors.fgVeryFaint,
            paddingLeft: 28,
          }}
        >
          Name
        </span>
        <span
          style={{
            fontSize: 11,
            fontWeight: 600,
            textTransform: "uppercase",
            letterSpacing: "0.05em",
            color: colors.fgVeryFaint,
            width: 70,
            textAlign: "right",
          }}
        >
          Type
        </span>
      </div>

      {/* Rows */}
      <div style={{ padding: "6px 8px" }}>
        {sec.items.map((item, i) => (
          <FileRow key={item.id} item={item} sectionType={sec.type} index={i} frame={frame} fps={fps} />
        ))}
      </div>
    </div>
  );
};

const FileRow: React.FC<{
  item: Section["items"][number];
  sectionType: keyof typeof PALETTE;
  index: number;
  frame: number;
  fps: number;
}> = ({ item, sectionType, index, frame, fps }) => {
  const start = T_FILES_START + 8 + index * 4;
  const enter = spring({
    frame: frame - start,
    fps,
    config: { damping: 24, stiffness: 180, mass: 0.5 },
  });
  const opacity = interpolate(enter, [0, 1], [0, 1]);
  const tx = interpolate(enter, [0, 1], [-8, 0]);

  const pal = PALETTE[sectionType];
  const dotColor =
    item.sentiment === "positive"
      ? "#16a34a"
      : item.sentiment === "negative"
        ? "#dc2626"
        : item.sentiment
          ? "#6b7280"
          : null;

  // Highlight a specific row near the end (Sarah Chen)
  const highlight = index === 0 ? interpolate(frame, [T_FILES_START + 60, T_FILES_START + 75], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  }) : 0;
  const bg = highlight ? `${pal[3]}14` : "transparent";

  return (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        gap: 12,
        padding: "10px 12px",
        borderRadius: 8,
        background: bg,
        outline: highlight ? `1.5px solid ${pal[3]}44` : "none",
        opacity,
        transform: `translateX(${tx}px)`,
      }}
    >
      <svg width="18" height="22" viewBox="0 0 18 22" fill="none" style={{ flexShrink: 0 }}>
        <rect x="1" y="1" width="14" height="19" rx="3" fill={`${pal[1]}40`} stroke={pal[3]} strokeWidth="1.2" />
        <path d="M10 1v5h5" stroke={pal[3]} strokeWidth="1.2" strokeLinejoin="round" />
        <rect x="3.5" y="9" width="9" height="1.5" rx="0.75" fill={pal[3]} opacity="0.5" />
        <rect x="3.5" y="12" width="6.5" height="1.5" rx="0.75" fill={pal[3]} opacity="0.35" />
      </svg>
      <span
        style={{
          flex: 1,
          fontSize: 13.5,
          fontWeight: highlight ? 500 : 400,
          color: colors.fg,
          whiteSpace: "nowrap",
          overflow: "hidden",
          textOverflow: "ellipsis",
        }}
      >
        {dotColor && (
          <span
            style={{
              width: 8,
              height: 8,
              background: dotColor,
              display: "inline-block",
              borderRadius: 999,
              marginRight: 8,
              verticalAlign: "middle",
            }}
          />
        )}
        {item.label}
      </span>
      <span
        style={{
          fontSize: 11,
          color: "#bbb",
          flexShrink: 0,
          textTransform: "capitalize",
          width: 70,
          textAlign: "right",
        }}
      >
        {sectionType}
      </span>
    </div>
  );
};

// ── Animated cursor ──────────────────────────────────────────────────────────

const Cursor: React.FC<{ frame: number }> = ({ frame }) => {
  // Cursor appears just before hover starts, glides toward the People folder,
  // then fades out after the click.
  const startVisible = T_HOVER_START - 20;
  const endVisible = T_CLICK + 14;

  const opacity = interpolate(
    frame,
    [startVisible, startVisible + 8, endVisible - 6, endVisible],
    [0, 1, 1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" },
  );

  // Cursor target is over the first folder card (top-left of grid area).
  // Coordinates inside the body padding box: ~(140, 140)
  const x = interpolate(
    frame,
    [startVisible, T_HOVER_START + 14, T_CLICK],
    [560, 200, 180],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" },
  );
  const y = interpolate(
    frame,
    [startVisible, T_HOVER_START + 14, T_CLICK],
    [420, 160, 150],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" },
  );
  const scale = interpolate(frame, [T_CLICK - 3, T_CLICK + 1, T_CLICK + 8], [1, 0.85, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  return (
    <div
      style={{
        position: "absolute",
        top: 0,
        left: 0,
        transform: `translate(${x}px, ${y}px) scale(${scale})`,
        opacity,
        pointerEvents: "none",
        filter: "drop-shadow(0 4px 8px rgba(0,0,0,0.25))",
      }}
    >
      <svg width="28" height="28" viewBox="0 0 28 28">
        <path
          d="M5 3 L22 14 L14 16 L11 24 Z"
          fill="#0a0a0a"
          stroke="#ffffff"
          strokeWidth="1.4"
          strokeLinejoin="round"
        />
      </svg>
    </div>
  );
};

