import React from "react";
import {
  AbsoluteFill,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { AppShell } from "../components/AppShell";
import { colors } from "../theme";

const QUERY = "Senior engineers with more than 3 open tickets";

const CASCADE_STEPS = [
  "Embedded query · 384-dim vector against pgvector HNSW",
  "Filtered to entity_type = person, role ⊃ engineer",
  "Joined facts: ticket_count > 3 (live, bi-temporal)",
  "Ranked by graph centrality + recency decay",
];

type Match = {
  name: string;
  type: string;
  score: number;
  connections: number;
  tickets: number;
};

const MATCHES: Match[] = [
  { name: "Sarah Chen", type: "person", score: 92.4, connections: 47, tickets: 8 },
  { name: "Marcus Rivera", type: "person", score: 88.1, connections: 31, tickets: 6 },
  { name: "Aisha Patel", type: "person", score: 84.7, connections: 52, tickets: 5 },
  { name: "Jin Watanabe", type: "person", score: 81.2, connections: 28, tickets: 4 },
];

// Timeline (frames @ 30fps), scene-local
const T_HEADER = 4;
const T_INIT_MSG = 14;
const T_TYPE_START = 36;
const T_TYPE_END = 96; // user query typed
const T_USER_BUBBLE = 100;
const T_THINKING = 110;
const T_RESPONSE = 160;
const T_CASCADE = 180;
const T_MATCHES = 240;

export const SearchScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  return (
    <AbsoluteFill style={{ background: colors.background }}>
      <AppShell active="overview">
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            flex: 1,
            color: "#0f172a",
            background:
              "radial-gradient(ellipse 90% 60% at 0% 0%, #E8F1FE 0%, transparent 55%), radial-gradient(ellipse 70% 50% at 100% 0%, #FDE8E8 0%, transparent 50%), radial-gradient(ellipse 80% 70% at 50% 100%, #EFE5FE 0%, transparent 55%), #F7F3FB",
          }}
        >
          {/* Header */}
          <Header />

          {/* Chat container */}
          <main style={{ display: "flex", flex: 1, overflow: "hidden", padding: "0 64px 48px" }}>
            <div
              style={{
                margin: "0 auto",
                width: "100%",
                maxWidth: 980,
                display: "flex",
                flexDirection: "column",
                flex: 1,
                overflow: "hidden",
              }}
            >
              <div
                style={{
                  flex: 1,
                  display: "flex",
                  flexDirection: "column",
                  gap: 20,
                  overflow: "hidden",
                  paddingBottom: 24,
                }}
              >
                {/* Initial assistant greeting */}
                <AssistantBubble appearAt={T_INIT_MSG} fps={fps}>
                  Ask me anything based on the company context.
                </AssistantBubble>

                {/* User message — types in then becomes a bubble */}
                <UserBubble fps={fps} />

                {/* Thinking indicator */}
                <ThinkingBubble fps={fps} />

                {/* Assistant response */}
                <ResponseBubble fps={fps} />
              </div>

