const ThinkingBubble: React.FC<{ fps: number }> = ({ fps }) => {
  const frame = useCurrentFrame();
  const visibleStart = T_THINKING;
  const visibleEnd = T_RESPONSE - 4;
  if (frame < visibleStart || frame > visibleEnd) return null;

  const enter = spring({
