const InputBar: React.FC<{ frame: number }> = ({ frame }) => {
  const charsShown = Math.floor(
    interpolate(frame, [T_TYPE_START, T_TYPE_END], [0, QUERY.length], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    }),
  );
  // After bubble lifts off, input clears
  const cleared = frame >= T_USER_BUBBLE;
  const text = cleared ? "" : QUERY.slice(0, charsShown);

  // Caret blink
  const showCaret = !cleared && Math.floor(frame / 8) % 2 === 0;

