        style={{
          display: "flex",
          alignItems: "center",
          gap: 12,
          borderRadius: 999,
          border: "1px solid rgba(255,255,255,0.6)",
          background: "rgba(255,255,255,0.72)",
          padding: 8,
          boxShadow: "0 2px 24px rgba(15,23,42,0.05)",
          backdropFilter: "blur(18px)",
          WebkitBackdropFilter: "blur(18px)",
        }}
      >
        <div
          style={{
            flex: 1,
            padding: "0 16px",
            fontSize: 14,
            color: text ? "#0f172a" : "#94a3b8",
            display: "flex",
            alignItems: "center",
            minHeight: 36,
          }}
        >
          {text || 'e.g. "Senior engineers with more than 3 open tickets"'}
          {showCaret && (
            <span
              style={{
                display: "inline-block",
                width: 1.5,
                height: 16,
                background: "#0f172a",
                marginLeft: 2,
              }}
            />
          )}
        </div>
        <div
          style={{
            width: 36,
            height: 36,
            borderRadius: 999,
            background: "#0f172a",
            color: "white",
            display: "grid",
            placeItems: "center",
            transform: `scale(${sendScale})`,
            flexShrink: 0,
          }}
        >
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <line x1="22" y1="2" x2="11" y2="13" />
            <polygon points="22 2 15 22 11 13 2 9 22 2" />
          </svg>
        </div>
      </div>
    </div>
  );
};

