import { AppShell } from "../components/AppShell";
import { colors } from "../theme";

const QUERY = "Senior engineers with more than 3 open tickets";

const CASCADE_STEPS = [
  "Embedded query · 384-dim vector against pgvector HNSW",
  "Filtered to entity_type = person, role ⊃ engineer",
  "Joined facts: ticket_count > 3 (live, bi-temporal)",
  "Ranked by graph centrality + recency decay",
];

type Match = {
  name: string;
  type: string;
  score: number;
  connections: number;
  tickets: number;
};

const MATCHES: Match[] = [
  { name: "Sarah Chen", type: "person", score: 92.4, connections: 47, tickets: 8 },
