  { name: "Aisha Patel", type: "person", score: 84.7, connections: 52, tickets: 5 },
  { name: "Jin Watanabe", type: "person", score: 81.2, connections: 28, tickets: 4 },
];

// Timeline (frames @ 30fps), scene-local
const T_HEADER = 4;
const T_INIT_MSG = 14;
const T_TYPE_START = 36;
const T_TYPE_END = 96; // user query typed
const T_USER_BUBBLE = 100;
const T_THINKING = 110;
const T_RESPONSE = 160;
const T_CASCADE = 180;
const T_MATCHES = 240;

export const SearchScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  return (
