import React from "react";
import {
  AbsoluteFill,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { AppShell } from "../components/AppShell";
import { colors } from "../theme";

// ── Palette mirrors web/src/pages/workflow/WorkflowPage.tsx ─────────────────
const NODE_PALETTE: Record<string, [string, string]> = {
  person: ["#3b82f6", "#fff"],
  company: ["#22c55e", "#fff"],
  communication: ["#a855f7", "#fff"],
  document: ["#f97316", "#fff"],
  task: ["#ec4899", "#fff"],
  policy: ["#14b8a6", "#fff"],
};

type N = { id: string; label: string; type: keyof typeof NODE_PALETTE; x: number; y: number; r: number };
type E = { source: string; target: string; label: string };

// Pre-computed force-directed layout — coords inside a 1000×600 viewBox
const NODES: N[] = [
  // Center cluster — Sarah (focus)
  { id: "sarah", label: "Sarah Chen", type: "person", x: 500, y: 300, r: 28 },

  // People
  { id: "marcus", label: "Marcus Rivera", type: "person", x: 350, y: 200, r: 22 },
  { id: "aisha", label: "Aisha Patel", type: "person", x: 660, y: 210, r: 22 },
  { id: "jin", label: "Jin Watanabe", type: "person", x: 720, y: 380, r: 20 },
  { id: "lena", label: "Lena Brandt", type: "person", x: 320, y: 410, r: 20 },

  // Companies
  { id: "acme", label: "Acme GmbH", type: "company", x: 180, y: 290, r: 24 },
  { id: "northwind", label: "Northwind", type: "company", x: 820, y: 280, r: 22 },

  // Communications
  { id: "comm1", label: "Q3 review", type: "communication", x: 470, y: 130, r: 16 },
  { id: "comm2", label: "Budget call", type: "communication", x: 600, y: 100, r: 16 },

  // Documents
  { id: "doc1", label: "Roadmap.pdf", type: "document", x: 130, y: 160, r: 16 },
  { id: "doc2", label: "Spec v2", type: "document", x: 880, y: 160, r: 16 },

  // Tasks
  { id: "t1", label: "Migrate auth", type: "task", x: 410, y: 470, r: 15 },
  { id: "t2", label: "Audit logs", type: "task", x: 580, y: 480, r: 15 },

  // Policy
  { id: "pol1", label: "GDPR", type: "policy", x: 870, y: 460, r: 18 },
];

const EDGES: E[] = [
  { source: "sarah", target: "marcus", label: "reports_to" },
  { source: "sarah", target: "aisha", label: "collaborates" },
  { source: "sarah", target: "acme", label: "works_at" },
  { source: "sarah", target: "comm1", label: "participated" },
  { source: "sarah", target: "comm2", label: "participated" },
  { source: "sarah", target: "t1", label: "owns" },
  { source: "sarah", target: "t2", label: "owns" },
  { source: "marcus", target: "acme", label: "works_at" },
  { source: "marcus", target: "doc1", label: "authored" },
  { source: "aisha", target: "northwind", label: "works_at" },
  { source: "aisha", target: "doc2", label: "reviewed" },
  { source: "jin", target: "northwind", label: "works_at" },
  { source: "jin", target: "comm2", label: "participated" },
  { source: "lena", target: "acme", label: "works_at" },
  { source: "lena", target: "t1", label: "assigned" },
  { source: "aisha", target: "pol1", label: "owns" },
  { source: "jin", target: "pol1", label: "reviews" },
];

// ── Timing ──────────────────────────────────────────────────────────────────
const T_TOOLBAR = 4;
const T_HALOS = 18;
const T_EDGES_START = 36;
const T_EDGES_END = 96;
const T_NODES_START = 30;
const T_INSPECTOR = 130;
const T_HIGHLIGHT = 160;

export const WorkflowScene: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const nodeMap = React.useMemo(() => new Map(NODES.map((n) => [n.id, n])), []);

  // Subtle camera zoom/pan — focus shifts toward Sarah's cluster over time
  const zoom = interpolate(frame, [T_HIGHLIGHT, T_HIGHLIGHT + 60], [1, 1.18], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  const camX = interpolate(frame, [T_HIGHLIGHT, T_HIGHLIGHT + 60], [0, -60], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  const camY = interpolate(frame, [T_HIGHLIGHT, T_HIGHLIGHT + 60], [0, -30], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  return (
    <AbsoluteFill style={{ background: colors.background }}>
      <AppShell active="sources">
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            flex: 1,
            background: colors.background,
            padding: "24px 32px",
            gap: 16,
          }}
        >
          {/* Toolbar */}
          <Toolbar />

          {/* Canvas + Inspector */}
          <div style={{ display: "flex", flex: 1, gap: 16, overflow: "hidden" }}>
            <div
              style={{
                flex: 1,
                borderRadius: 14,
                border: `1px solid ${colors.border}`,
                background: "#f8fafc",
                overflow: "hidden",
                position: "relative",
                boxShadow: "0 1px 6px rgba(0,0,0,0.04)",
              }}
            >
              <svg
                viewBox="0 0 1000 600"
                preserveAspectRatio="xMidYMid meet"
                style={{ width: "100%", height: "100%", display: "block" }}
              >
                <g transform={`translate(${camX} ${camY}) scale(${zoom}) translate(${(1 - 1) * 500}, ${(1 - 1) * 300})`}>
                  {/* Type halos */}
                  <Halos frame={frame} fps={fps} />

                  {/* Edges */}
                  {EDGES.map((e, i) => (
                    <Edge key={`${e.source}-${e.target}-${i}`} edge={e} index={i} nodeMap={nodeMap} frame={frame} fps={fps} />
                  ))}

                  {/* Nodes */}
                  {NODES.map((n, i) => (
                    <Node key={n.id} node={n} index={i} frame={frame} fps={fps} />
                  ))}

                  {/* Highlight ring on Sarah */}
                  <SarahHighlight nodeMap={nodeMap} frame={frame} />
                </g>
              </svg>

              {/* Legend */}
              <Legend />
            </div>

            <Inspector frame={frame} fps={fps} />
          </div>
        </div>
      </AppShell>
    </AbsoluteFill>
  );
};

// ── Subcomponents ────────────────────────────────────────────────────────────

const Toolbar: React.FC = () => {
  const frame = useCurrentFrame();
  const op = interpolate(frame, [T_TOOLBAR, T_TOOLBAR + 14], [0, 1], { extrapolateRight: "clamp" });
  const ty = interpolate(op, [0, 1], [-6, 0]);
  return (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        gap: 10,
        padding: "10px 14px",
        background: "#fff",
        borderRadius: 12,
        border: `1px solid ${colors.border}`,
        boxShadow: "0 1px 6px rgba(0,0,0,0.04)",
        opacity: op,
        transform: `translateY(${ty}px)`,
      }}
    >
      <span style={{ fontSize: 13, fontWeight: 600, color: "#0f172a" }}>Knowledge graph</span>
      <span style={{ fontSize: 12, color: "#64748b", marginLeft: 4 }}>· focus</span>
      <div
        style={{
          marginLeft: 8,
          padding: "5px 10px",
          background: "#f1f5f9",
          borderRadius: 8,
          fontSize: 12,
          color: "#0f172a",
          fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace",
        }}
      >
        person:sarah-chen
      </div>
      <div style={{ marginLeft: 8, fontSize: 12, color: "#64748b" }}>limit 200 · depth 2</div>

      <div style={{ marginLeft: "auto", display: "flex", gap: 8 }}>
        <ToolbarBtn label="Load Graph" primary />
        <ToolbarBtn label="Fit View" />
        <ToolbarBtn label="Edge Labels" />
      </div>
    </div>
  );
};

const ToolbarBtn: React.FC<{ label: string; primary?: boolean }> = ({ label, primary }) => (
  <div
    style={{
      padding: "6px 12px",
      borderRadius: 8,
      fontSize: 12.5,
      fontWeight: 500,
      background: primary ? "#0f172a" : "#fff",
      color: primary ? "#fff" : "#334155",
      border: primary ? "1px solid #0f172a" : `1px solid ${colors.border}`,
    }}
  >
    {label}
  </div>
);

const Halos: React.FC<{ frame: number; fps: number }> = ({ frame, fps }) => {
  // Cluster-style halos behind groups of same-type nodes
  const op = spring({ frame: frame - T_HALOS, fps, config: { damping: 24, stiffness: 100 } });
  const opacity = interpolate(op, [0, 1], [0, 0.18]);
  const groups: { type: keyof typeof NODE_PALETTE; cx: number; cy: number; r: number }[] = [
    { type: "person", cx: 500, cy: 300, r: 240 },
    { type: "company", cx: 200, cy: 285, r: 90 },
    { type: "company", cx: 820, cy: 290, r: 90 },
    { type: "communication", cx: 540, cy: 115, r: 110 },
    { type: "task", cx: 495, cy: 475, r: 120 },
  ];
  return (
    <>
      {groups.map((g, i) => (
        <circle
          key={i}
          cx={g.cx}
          cy={g.cy}
          r={g.r}
          fill={NODE_PALETTE[g.type][0]}
          opacity={opacity}
        />
      ))}
    </>
  );
};

const Edge: React.FC<{
  edge: E;
  index: number;
  nodeMap: Map<string, N>;
  frame: number;
  fps: number;
}> = ({ edge, index, nodeMap, frame, fps }) => {
  const a = nodeMap.get(edge.source);
  const b = nodeMap.get(edge.target);
  if (!a || !b) return null;

  // Curved quadratic
  const mx = (a.x + b.x) / 2;
  const my = (a.y + b.y) / 2;
  const dx = b.x - a.x;
  const dy = b.y - a.y;
  const len = Math.sqrt(dx * dx + dy * dy) || 1;
  const nx = -dy / len;
  const ny = dx / len;
  const offset = 12 * ((index % 3) - 1);
  const cx = mx + nx * offset;
  const cy = my + ny * offset;

  const start = T_EDGES_START + index * 2;
  const prog = interpolate(frame, [start, start + 18], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  // Animate path stroke-dashoffset
  const pathLen = Math.hypot(dx, dy) * 1.1;

  // Highlight Sarah's edges after T_HIGHLIGHT
  const isSarah = edge.source === "sarah" || edge.target === "sarah";
  const highlight = isSarah
    ? interpolate(frame, [T_HIGHLIGHT, T_HIGHLIGHT + 20], [0, 1], {
        extrapolateLeft: "clamp",
        extrapolateRight: "clamp",
      })
    : 0;

  const stroke = highlight ? `rgba(59,130,246,${0.55 + 0.3 * highlight})` : "rgba(100,116,139,0.42)";
  const strokeWidth = highlight ? 1.4 + 0.8 * highlight : 1.1;

  return (
    <path
      d={`M ${a.x} ${a.y} Q ${cx} ${cy} ${b.x} ${b.y}`}
      fill="none"
      stroke={stroke}
      strokeWidth={strokeWidth}
      strokeDasharray={pathLen}
      strokeDashoffset={pathLen * (1 - prog)}
      strokeLinecap="round"
    />
  );
};

const Node: React.FC<{ node: N; index: number; frame: number; fps: number }> = ({
  node,
  index,
  frame,
  fps,
}) => {
  const start = T_NODES_START + index * 4;
  const enter = spring({
    frame: frame - start,
    fps,
    config: { damping: 14, stiffness: 160, mass: 0.6 },
  });
  const scale = interpolate(enter, [0, 1], [0, 1]);
  const opacity = interpolate(enter, [0, 0.4], [0, 1], { extrapolateRight: "clamp" });
  const [fill, fg] = NODE_PALETTE[node.type] ?? ["#6b7280", "#fff"];

  // Subtle wobble for Sarah
  const isFocus = node.id === "sarah";
  const wobble = isFocus
    ? Math.sin((frame - T_HIGHLIGHT) * 0.18) * (frame > T_HIGHLIGHT ? 0.6 : 0)
    : 0;

  return (
    <g transform={`translate(${node.x} ${node.y}) scale(${scale + wobble * 0.01})`} opacity={opacity}>
      <circle r={node.r} fill={fill} stroke="#fff" strokeWidth={2.5} />
      <text
        x={0}
        y={node.r + 14}
        textAnchor="middle"
        fontSize={11}
        fontWeight={500}
        fill="#0f172a"
        style={{ paintOrder: "stroke", stroke: "rgba(255,255,255,0.95)", strokeWidth: 3 }}
      >
        {node.label}
      </text>
      {/* Inner accent ring */}
      <circle r={node.r - 4} fill="none" stroke={fg} strokeOpacity={0.35} strokeWidth={1} />
    </g>
  );
};

const SarahHighlight: React.FC<{ nodeMap: Map<string, N>; frame: number }> = ({ nodeMap, frame }) => {
  const sarah = nodeMap.get("sarah");
  if (!sarah) return null;
  const ringOpacity = interpolate(frame, [T_HIGHLIGHT, T_HIGHLIGHT + 14], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  // Pulsating outer ring
  const pulse = 1 + 0.06 * Math.sin((frame - T_HIGHLIGHT) * 0.22);
  return (
    <g transform={`translate(${sarah.x} ${sarah.y})`} opacity={ringOpacity}>
      <circle r={sarah.r + 10} fill="none" stroke="#3b82f6" strokeWidth={2} opacity={0.85} />
      <circle r={(sarah.r + 18) * pulse} fill="none" stroke="#3b82f6" strokeWidth={1.5} opacity={0.45} />
    </g>
  );
};

const Legend: React.FC = () => {
  const frame = useCurrentFrame();
  const op = interpolate(frame, [T_TOOLBAR + 6, T_TOOLBAR + 24], [0, 1], { extrapolateRight: "clamp" });
  const items: { label: string; type: keyof typeof NODE_PALETTE }[] = [
    { label: "Person", type: "person" },
    { label: "Company", type: "company" },
    { label: "Communication", type: "communication" },
    { label: "Document", type: "document" },
    { label: "Task", type: "task" },
    { label: "Policy", type: "policy" },
  ];
  return (
    <div
      style={{
        position: "absolute",
        bottom: 16,
        left: 16,
        display: "flex",
        gap: 10,
        flexWrap: "wrap",
        background: "rgba(255,255,255,0.92)",
        border: `1px solid ${colors.border}`,
        borderRadius: 10,
        padding: "8px 12px",
        boxShadow: "0 1px 6px rgba(0,0,0,0.04)",
        opacity: op,
      }}
    >
      {items.map((it) => (
        <div key={it.type} style={{ display: "inline-flex", alignItems: "center", gap: 6 }}>
          <span
            style={{
              width: 8,
              height: 8,
              borderRadius: 999,
              background: NODE_PALETTE[it.type][0],
              display: "inline-block",
            }}
          />
          <span style={{ fontSize: 11.5, color: "#475569" }}>{it.label}</span>
        </div>
      ))}
    </div>
  );
};

const Inspector: React.FC<{ frame: number; fps: number }> = ({ frame, fps }) => {
  const enter = spring({
    frame: frame - T_INSPECTOR,
    fps,
    config: { damping: 22, stiffness: 130, mass: 0.6 },
  });
  const op = interpolate(enter, [0, 1], [0, 1]);
  const tx = interpolate(enter, [0, 1], [16, 0]);

  const facts: { k: string; v: string; conf: number }[] = [
    { k: "role", v: "Senior Engineer", conf: 0.96 },
    { k: "works_at", v: "Acme GmbH", conf: 0.92 },
    { k: "tickets_open", v: "8", conf: 0.99 },
    { k: "manager", v: "Marcus Rivera", conf: 0.88 },
    { k: "languages", v: "Go, TypeScript", conf: 0.81 },
  ];

  return (
    <div
      style={{
        width: 340,
        flexShrink: 0,
        background: "#fff",
        borderRadius: 14,
        border: `1px solid ${colors.border}`,
        boxShadow: "0 1px 6px rgba(0,0,0,0.04)",
        padding: "18px 18px",
        opacity: op,
        transform: `translateX(${tx}px)`,
        display: "flex",
        flexDirection: "column",
        gap: 12,
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <span
          style={{
            width: 12,
            height: 12,
            borderRadius: 999,
            background: NODE_PALETTE.person[0],
          }}
        />
        <p style={{ margin: 0, fontSize: 16, fontWeight: 600, color: "#0f172a" }}>Sarah Chen</p>
      </div>
      <div style={{ display: "flex", gap: 6 }}>
        <span
          style={{
            fontSize: 11,
            fontWeight: 600,
            background: "#dbeafe",
            color: "#1d4ed8",
            padding: "3px 8px",
            borderRadius: 999,
          }}
        >
          person
        </span>
        <span
          style={{
            fontSize: 11,
            fontWeight: 600,
            background: "#f1f5f9",
            color: "#475569",
            padding: "3px 8px",
            borderRadius: 999,
          }}
        >
          47 connections
        </span>
      </div>

      <div style={{ height: 1, background: colors.borderSoft, margin: "4px 0" }} />

      <p style={{ margin: 0, fontSize: 11, fontWeight: 600, color: "#94a3b8", textTransform: "uppercase", letterSpacing: "0.05em" }}>
        Facts
      </p>

      {facts.map((f, i) => {
        const start = T_INSPECTOR + 6 + i * 5;
        const e = spring({
          frame: frame - start,
          fps,
          config: { damping: 24, stiffness: 180, mass: 0.5 },
        });
        const fOp = interpolate(e, [0, 1], [0, 1]);
        const fTy = interpolate(e, [0, 1], [4, 0]);
        return (
          <div
            key={f.k}
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              gap: 8,
              padding: "8px 10px",
              borderRadius: 10,
              background: "#f8fafc",
              border: `1px solid ${colors.borderSoft}`,
              opacity: fOp,
              transform: `translateY(${fTy}px)`,
            }}
          >
            <div style={{ minWidth: 0 }}>
              <p style={{ margin: 0, fontSize: 11, color: "#94a3b8", fontWeight: 500 }}>{f.k}</p>
              <p style={{ margin: "1px 0 0", fontSize: 13, color: "#0f172a", fontWeight: 500 }}>{f.v}</p>
            </div>
            <ConfPill v={f.conf} />
          </div>
        );
      })}
    </div>
  );
};

const ConfPill: React.FC<{ v: number }> = ({ v }) => {
  const pct = Math.round(v * 100);
  const tone = v >= 0.9 ? "#16a34a" : v >= 0.8 ? "#0ea5e9" : "#f59e0b";
  return (
    <span
      style={{
        fontSize: 11,
        fontWeight: 600,
        color: tone,
        background: `${tone}1A`,
        padding: "2px 8px",
        borderRadius: 999,
        flexShrink: 0,
      }}
    >
      {pct}%
    </span>
  );
};

