import React from "react";
import { AbsoluteFill, Sequence, useCurrentFrame, interpolate } from "remotion";
import { BrowseScene } from "./BrowseScene";
import { SearchScene } from "./SearchScene";
import { WorkflowScene } from "./WorkflowScene";

const SCENE_DURATIONS = {
  browse: 360,
  search: 360,
  workflow: 360,
};
const TRANSITION = 18; // frame overlap for crossfade

const SCENES: { component: React.FC; duration: number }[] = [
  { component: BrowseScene, duration: SCENE_DURATIONS.browse },
  { component: SearchScene, duration: SCENE_DURATIONS.search },
  { component: WorkflowScene, duration: SCENE_DURATIONS.workflow },
];

export const MasterComposition: React.FC = () => {
  return (
    <AbsoluteFill>
      {SCENES.reduce<{ items: React.ReactNode[]; offset: number }>(
        (acc, scene, i) => {
          const Comp = scene.component;
          const isLast = i === SCENES.length - 1;
          // Each scene starts at offset, lasts duration, with crossfade overlap
          const from = acc.offset;
          acc.items.push(
            <Sequence
              key={i}
              from={from}
              durationInFrames={scene.duration}
              layout="none"
            >
              <SceneFader duration={scene.duration} fadeIn={i > 0 ? TRANSITION : 8} fadeOut={isLast ? 0 : TRANSITION}>
                <Comp />
              </SceneFader>
            </Sequence>,
          );
          acc.offset += scene.duration - (isLast ? 0 : TRANSITION);
          return acc;
        },
        { items: [], offset: 0 },
      ).items}
    </AbsoluteFill>
  );
};

const SceneFader: React.FC<{
  duration: number;
  fadeIn: number;
  fadeOut: number;
  children: React.ReactNode;
}> = ({ duration, fadeIn, fadeOut, children }) => {
  const frame = useCurrentFrame();
  const inOp = fadeIn > 0 ? interpolate(frame, [0, fadeIn], [0, 1], { extrapolateRight: "clamp" }) : 1;
  const outOp =
    fadeOut > 0
      ? interpolate(frame, [duration - fadeOut, duration], [1, 0], { extrapolateLeft: "clamp" })
      : 1;
  return <AbsoluteFill style={{ opacity: inOp * outOp }}>{children}</AbsoluteFill>;
};

// Total frames = sum(durations) - (n-1)*TRANSITION
export const MASTER_DURATION =
  SCENES.reduce((s, x) => s + x.duration, 0) - (SCENES.length - 1) * TRANSITION;

